#include <stdio.h>

int main() {
    int t;
    scanf("%d", &t); // Read number of test cases
    while (t--) {
        int n;
        scanf("%d", &n); // Read the size of the array
        int arr[n]; // Declare an array with a fixed size, assuming a max of 1000 elements
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]); // Read array elements
        }

        int dp[101] = {0}; // Declare dp array with fixed size, initialized to 0
        dp[n - 1] = 1; // The last element can always form a subsequence of length 1

        // Fill the dp array
        for (int i = n - 2; i >= 0; i--) {
            int is_lt = 0; // Use an integer for boolean comparison
            for (int j = i + 1; j < n; j++) {
                if (arr[i] <= arr[j]) {
                    dp[i] = dp[j] + 1 > dp[i] ? dp[j] + 1 : dp[i];
                    is_lt = 1; // Set flag to indicate there is a valid greater element
                }
            }
            if (is_lt == 0) {
                dp[i] = 1; // No greater element found, set length to 1
            }
        }

        // Find the maximum value in the dp array
        int max_length = 0;
        for (int i = 0; i < n; i++) {
            if (dp[i] > max_length) {
                max_length = dp[i];
            }
        }

        printf("%d\n", max_length); // Output the result
    }

    return 0;
}

