import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int t = scanner.nextInt(); // Read number of test cases
        while (t-- > 0) {
            int n = scanner.nextInt(); // Read the size of the array
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt(); // Read array elements
            }

            int[] dp = new int[n]; // Create a dp array to store lengths
            Arrays.fill(dp, 0); // Initialize dp array to 0

            dp[n - 1] = 1; // The last element is a subsequence of length 1

            for (int i = n - 2; i >= 0; i--) {
                boolean is_lt = false; // Flag to check if any larger element found
                for (int j = i + 1; j < n; j++) {
                    if (arr[i] <= arr[j]) { // Check for non-decreasing condition
                        dp[i] = Math.max(dp[j] + 1, dp[i]); // Update dp[i]
                        is_lt = true; // Found a larger or equal element
                    }
                }
                if (!is_lt) {
                    dp[i] = 1; // No larger or equal element found
                }
            }
            Arrays.sort(dp); // Sort dp array to find the largest length
            System.out.println(dp[n - 1]); // Output the result
        }
        scanner.close(); // Close scanner
    }
}

