const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let inputLines = [];
let currentLine = 0;

// Function to process the input
function processInput() {
    let t = parseInt(inputLines[currentLine++]); // Number of test cases

    while (t--) {
        let n = parseInt(inputLines[currentLine++]); // Size of the array
        let arr = inputLines[currentLine++].split(' ').map(Number); // Array input

        let dp = new Array(n).fill(0);

        dp[n - 1] = 1;

        // Compute the DP array values
        for (let i = n - 2; i >= 0; i--) {
            let is_lt = false;
            for (let j = i + 1; j < n; j++) {
                if (arr[i] <= arr[j]) {
                    dp[i] = Math.max(dp[j] + 1, dp[i]);
                    is_lt = true;
                }
            }
            if (!is_lt) {
                dp[i] = 1;
            }
        }

        // Sort the DP array and print the result
        dp.sort((a, b) => a - b);
        console.log(dp[n - 1]);
    }
}

// Reading the input
rl.on('line', (line) => {
    inputLines.push(line);
}).on('close', () => {
    processInput(); // Call the function after input reading is done
});
